1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Customer = { yearsWithMHPCO: number };
4	type Scenario = { customer: Customer; steps: Step[] };
5	type QuoteResult = { premium: number };
6	
7	const PROCESSING_FEE = 5;
8	const FIRST_INSURANCE_RATE = 0.1;
9	
10	const BASE_PREMIUMS: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	};
14	
15	const quoteStep = (step: Step): QuoteResult => {
16	  const itemsBase = step.items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
17	  const firstInsurance = itemsBase * FIRST_INSURANCE_RATE;
18	  const premium = Math.ceil(itemsBase + firstInsurance) + PROCESSING_FEE;
19	  return { premium };
20	};
21	
22	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
23	  const results = scenario.steps.map(quoteStep);
24	  return { results };
25	};
26

1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Quote — empty and basic items
6	  it("empty item list yields premium of 5 G (processing fee only)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
