14	    const result = runScenario({
15	      customer: { yearsWithMHPCO: 0 },
16	      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] }],
17	    });
18	    expect(result).toEqual({ results: [{ premium: 115 }] });
19	  });
20	  it("a single plain amulet yields premium of 71 G (60 + 6 + 5)", () => {
21	    const result = runScenario({
22	      customer: { yearsWithMHPCO: 0 },
23	      steps: [{ op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }] }],
24	    });
25	    expect(result).toEqual({ results: [{ premium: 71 }] });
26	  });
27	  it.todo("a single plain staff yields premium of 93 G (80 + 8 + 5)");
28	  it.todo("a single plain potion yields premium of 49 G (40 + 4 + 5)");
29	
30	  // Components and building blocks
31	  it.todo("a single rune component yields premium of 33 G (25 + 3 + 5)");
32	  it.todo("two runes yield premium of 60 G (50 + 5 + 5)");
33	  it.todo("three alike runes form a block: premium 71 G (60 + 6 + 5)");
34	  it.todo("four runes: no block, premium 115 G (100 + 10 + 5)");
35	  it.todo("two runes + one moonstone: no block, premium 88 G (75 + 7.5→8 + 5)");
36	  it.todo("three runes + three moonstones: two blocks, premium 137 G (120 + 12 + 5)");
37	
38	  // Per-item modifiers
39	  it.todo("a cursed sword (newcomer): premium 165 G");
40	  it.todo("a sword with enchantment 5 adds 30% surcharge");
41	  it.todo("a sword with enchantment 4 adds no surcharge");
42	  it.todo("a cursed sword with enchantment 5 stacks both surcharges");
43	
44	  // Policy-wide modifiers
45	  it.todo("loyalty discount (≥2 years) applies to policy base premium");
46	  it.todo("loyalty discount at exactly 2 years applies");
47	  it.todo("follow-up contract applies 15% discount after first quote");
48	  it.todo("multi-item policy: cursed surcharge applies only to cursed item's base premium");
49	
50	  // Rounding
51	  it.todo("premium rounds up (in MHPCO's favor)");
52	
53	  // Claims — basic
54	  it.todo("standard claim on plain sword: 500 damage → payout 400, cap depletes by 400");
55	  it.todo("claim on rune (no enchantment/material): 200 damage → payout 100");
56	  it.todo("high-enchantment item (≥8): 50% reimbursement, then deductible");
57	  it.todo("dragon-material item: full reimbursement, then deductible");
58	  it.todo("high enchantment + dragon material: 50% rule wins, then deductible");
59	  it.todo("deductible applies per damage entry (multiple items damaged)");
60	
61	  // Cap and multi-item
62	  it.todo("policy cap is 2× insurance sum");
63	  it.todo("two-claim scenario: cap depletes across claims");
64	  it.todo("multiple items of same type: each damage entry has its own deductible");
65	
66	  // Errors
67	  it.todo("unknown item type in quote → CLI exits non-zero");
68	  it.todo("claim references item not on policy → CLI exits non-zero");
69	  it.todo("damage with negative amount → CLI exits non-zero");
70	  it.todo("too many damage entries of a given type → CLI exits non-zero");
71	
72	  // Integration
73	  it.todo("newcomer with cursed sword: 165 G");
